#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long d; scanf("%lld", &d);
        long long r = d % 9;
        if (r == 0) printf("1\n");
        else printf("%lld\n", r + 1);
    }
    return 0;
}

